import type { MechanicExecFn, MechanicExecContext, MechanicExecResult } from '../types';

// ─────────────────────────────────────────────────────────────────────────────
// STUB FACTORY
// Returns a no-op exec function for mechanics without compiled implementations.
// ─────────────────────────────────────────────────────────────────────────────

function stubExec(mechanicId: string, execHook: string): MechanicExecFn {
  return function execStub(ctx: MechanicExecContext): MechanicExecResult {
    return {
      mechanicId,
      execHook,
      fired:           false,
      outputs:         {},
      telemetryEvents: [],
      errorMessage:    undefined,
      executionMs:     0,
    };
  };
}

