// ─────────────────────────────────────────────────────────────────────────────
// REGISTRY ACCESSOR
// MechanicsBridge calls getExecFn() — never accesses EXEC_REGISTRY directly.
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Retrieve the exec function for a given exec_hook ID.
 *
 * @param execHook - The exec_hook string from MechanicRecord
 * @param mechanicId - Used only for stub construction (fallback label)
 * @returns Compiled exec function if available, stub otherwise
 */
export function getExecFn(execHook: string, mechanicId: string): MechanicExecFn {
  return EXEC_REGISTRY[execHook] ?? stubExec(mechanicId, execHook);
}

/**
 * Check whether a compiled exec function exists for this exec_hook.
 * Used by MechanicsBridge to distinguish compiled vs stub mechanics.
 */
export function hasCompiledExec(execHook: string): boolean {
  return Object.prototype.hasOwnProperty.call(EXEC_REGISTRY, execHook);
}

/**
 * Count how many exec hooks have compiled implementations.
 * Logged by MechanicsRouter at init time.
 */
export function getCompiledExecCount(): number {
  return Object.keys(EXEC_REGISTRY).length;
}

/**
 * List all registered exec hook IDs.
 * Used by build verification and DevPanel.
 */
export function listRegisteredExecHooks(): string[] {
  return Object.keys(EXEC_REGISTRY);
}